#include <stdio.h>
#include <math.h>
int main() {
    int n;
    scanf("%d", &n);
    int count = 0;
    for (int i = 1; i <= sqrt(n); i++) {
        if (n % i == 0) {
            if (n / i == i) {
                count++;
            } else {
                count += 2;
            }
        }
    }
    printf("%d\n", count);
    return 0;
}

